// POLONIUM trusted-relationship initial access → tunnel/proxy install within 30 min
let LookbackDays = 14d;
let WindowMin = 30m;
let TunnelBins = dynamic(["plink.exe","chisel.exe","ligolo.exe","ligolo-ng.exe","ngrok.exe","frpc.exe","frps.exe","meshagent.exe","meshagent64.exe","socat.exe","revsocks.exe"]);
let TunnelCmdTokens = dynamic(["chisel client","chisel server","ligolo","ngrok tcp","ngrok http","plink"," -R 0.0.0.0"," -R *:*:","frpc.ini","meshcentral"]);
// 1. Successful remote-interactive logons (RDP / VPN-pivoted) — POLONIUM's documented initial vector
let RemoteLogons =
    DeviceLogonEvents
    | where Timestamp > ago(LookbackDays)
    | where ActionType == "LogonSuccess"
    | where LogonType in ("RemoteInteractive","Network","NetworkCleartext")
    | where AccountName !endswith "$"
    | where RemoteIPType == "Public" or isnotempty(RemoteIP)
    | project LogonTime = Timestamp, DeviceId, DeviceName, AccountName, AccountDomain,
              RemoteIP, LogonType, Protocol;
// 2. Tunnel / reverse-proxy execution
let TunnelExec =
    DeviceProcessEvents
    | where Timestamp > ago(LookbackDays)
    | where AccountName !endswith "$"
    | where FileName in~ (TunnelBins)
       or (FileName in~ ("powershell.exe","pwsh.exe","cmd.exe") and ProcessCommandLine has_any (TunnelCmdTokens))
       or (ProcessCommandLine has " -R " and ProcessCommandLine has_any (":22",":443",":3389","0.0.0.0:"))
    | project ProcTime = Timestamp, DeviceId, DeviceName, AccountName,
              ProcFile = FileName, ProcCmd = ProcessCommandLine,
              Parent = InitiatingProcessFileName,
              ParentCmd = InitiatingProcessCommandLine,
              IsRemoteSession = tostring(parse_json(AdditionalFields).IsInitiatingProcessRemoteSession);
RemoteLogons
| join kind=inner TunnelExec on DeviceId, AccountName
| where ProcTime between (LogonTime .. LogonTime + WindowMin)
| extend DelaySec = datetime_diff('second', ProcTime, LogonTime)
| project LogonTime, ProcTime, DelaySec, DeviceName, AccountName, RemoteIP,
          LogonType, Protocol, ProcFile, ProcCmd, Parent, ParentCmd, IsRemoteSession
| order by LogonTime desc
